INSERT INTO "GbQcRoastLog" (
  "batchNumber",
  "processingType",
  "roastedAt",
  "roastedBy",
  "notes",
  "roastProfile",
  "endTemp",
  "firstCrackMinutes",
  "createdAt"
)
SELECT
  s.batch_number,
  pp."processingType",
  s.roasted_at,
  NULLIF(s.roasted_by, ''),
  NULLIF(s.notes, ''),
  NULLIF(s.roast_profile, ''),
  s.end_temp,
  s.first_crack_minutes,
  NOW()
FROM roast_import_staging s
INNER JOIN LATERAL (
  SELECT "processingType"
  FROM "PreprocessingData"
  WHERE "batchNumber" = s.batch_number
  ORDER BY id ASC
  LIMIT 1
) pp ON true;

COMMIT;
